window.batmanCharacters=[{name:"Batman",identity:"Bruce Wayne",role:"The Dark Knight & Protector of Gotham",description:"Driven by a childhood tragedy, he uses his intellect, martial arts mastery, and high-tech arsenal to fight crime.",img:"../img/batman.avif"},{name:"Robin",identity:"Dick Grayson",role:"The Boy Wonder & Loyal Partner",description:"An expert acrobat who balances Batman's darkness with energy and hope.",img:"../img/robin.avif"},{name:"Batgirl",identity:"Barbara Gordon",role:"The Brilliant Crime-Fighter",description:"The Commissioner's daughter. She is an exceptionally intelligent hero who operates with her own unique style.",img:"../img/batGirl.avif"},{name:"Alfred Pennyworth",identity:"Alfred Pennyworth",role:"The Loyal Butler & Father Figure",description:"The backbone of Wayne Manor. He provides medical aid, tactical advice, and emotional support to Bruce.",img:"../img/alfret.avif"},{name:"Commissioner James Gordon",identity:"Jim Gordon",role:"Batman's Primary Contact in the GCPD",description:"One of the few honest cops in Gotham. He trusts Batman to do what the law cannot.",img:"../img/gordon.avif"},{name:"Detective Harvey Bullock",identity:"Harvey Bullock",role:"The Gruff Detective",description:"A rough-around-the-edges cop who initially distrusts vigilantes but ultimately seeks true justice.",img:"../img/harvey.avif"},{name:"The Joker",identity:"Unknown",role:"The Ultimate Arch-nemesis",description:"The Clown Prince of Crime. He uses lethal gags and unpredictable chaos to challenge Batman's morality.",img:"../img/joker.avif"},{name:"Harley Quinn",identity:"Dr. Harleen Quinzel",role:"The Joker's Right-Hand & Partner",description:"A former psychiatrist who fell in love with the Joker. She is known for her acrobatic combat and chaotic energy.",img:"../img/harley.avif"},{name:"Bane",identity:"Unknown",role:"The Brilliant Tactician",description:"A physical powerhouse and strategic mastermind who uses Venom to gain immense strength.",img:"../img/bane.avif"},{name:"Two-Face",identity:"Harvey Dent",role:"The Fallen D.A.",description:"Once Gotham's White Knight, a tragic accident split his personality into two.",img:"../img/twoFace.avif"},{name:"Ra's al Ghul",identity:"Ra's al Ghul",role:"The Immortal Leader of the League of Shadows",description:"An eco-terrorist who seeks to save the planet by eradicating modern civilization.",img:"../img/ghul.avif"},{name:"Clayface",identity:"Matt Hagen",role:"The Shapeshifting Menace",description:"A former actor turned into living clay, able to reshape himself and mimic others.",img:"../img/clayface.avif"},{name:"Catwoman",identity:"Selina Kyle",role:"The Expert Thief",description:"A burglar with a complex relationship with Batman.",img:"../img/catWoman.avif"},{name:"The Penguin",identity:"Oswald Cobblepot",role:"The Aristocrat of Crime",description:"A refined criminal mastermind operating under high society.",img:"../img/penguin.avif"},{name:"Scarecrow",identity:"Jonathan Crane",role:"The Master of Fear",description:"Uses fear toxin to make victims face their worst nightmares.",img:"../img/scarecrow.avif"},{name:"The Riddler",identity:"Edward Nygma",role:"The Master of Puzzles",description:"Leaves riddles to prove his intelligence over Batman.",img:"../img/riddler.avif"},{name:"Killer Croc",identity:"Waylon Jones",role:"The Reptilian Criminal",description:"A sewer-dwelling criminal with a crocodile-like appearance.",img:"../img/croc.avif"},{name:"Mr. Freeze",identity:"Victor Fries",role:"The Tragic Scientist",description:"Driven to save his frozen wife, Nora.",img:"../img/freeze.avif"},{name:"Poison Ivy",identity:"Pamela Isley",role:"The Eco-Terrorist",description:"Uses plants and pheromones to protect the environment.",img:"../img/poison.avif"}];